VALUES
  ('pukao-6f0ba476-moex-00369', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲將屬於乙所有之A動產，以自己名義讓與知情之丙。該讓與A動產之行為效力如何？', '["效力未定", "無效", "得撤銷", "有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00370', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲於路上遇到欠其新臺幣2000萬元並躲避不見面之乙，甲見機會難得，要求乙一起到警察局，乙 拒絕後甲欲強行帶乙到警察局，乙為逃亡，偷騎丙未熄火之機車，騎車逃逸，並事後丟棄於荒郊。 下列敘述何者錯誤？', '["乙偷騎丙未熄火之機車，為正當防衛之行為", "甲欲強行帶乙到警察局之行為，屬於拘束乙自由之行為", "甲之行為屬於自助行為", "丙得對乙主張侵害所有權之損害賠償"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00371', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲所有A土地及建造於A地上之B屋。甲將B屋出售予乙，並完成移轉所有權登記後，就房屋 得使用期限內，甲、乙間之法律關係如何？', '["視為有法定地上權關係", "推定有法定地上權關係", "視為有租賃關係", "推定為有租賃關係"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00372', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於特殊侵權行為責任主體，下列敘述何者錯誤？', '["數人相約飆車超速發生車禍，為民法第185條第1項後段規定之共同行為人", "土地上之建築物或其他工作物之借用人，為民法第191條規定之責任主體", "實施生產、製造及加工業者，為民法第191條之1規定之責任主體", "動力車輛之駕駛人，為民法第191條之2規定之責任主體"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00373', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於承攬之工作物瑕疵擔保責任，下列敘述何者錯誤？', '["定作人受領有瑕疵之工作物後，其仍得依民法第493條規定主張瑕疵修補請求權", "承攬之工作為建築物或其他土地上之工作物時，承攬人無可歸責事由而致工作物存有重大瑕疵 致不能達使用目的時，定作人仍得解除契約", "定作人依民法第495條第1項請求之損害範圍，包括工作瑕疵給付", "依民法第495條第1項定作人之損害賠償請求權，因瑕疵發見後6個月不行使而消滅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00374', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '依民法規定，下列何者不屬於社團之社員總會權限？', '["開除社員", "任免董事", "變更章程", "法人登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00375', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於普通地上權之地租，下列敘述何者正確？', '["以公共建設為目的而成立地上權者，不得約定地租", "地上權有支付地租之約定者，地上權人得隨時拋棄其權利", "土地所有權讓與時，關於已預付之地租，於第三人亦有效力", "當事人有支付地租之約定者，地上權人得支付未到期之3年分地租後，拋棄其權利 42050"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00376', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列何種物權，其成立非因當事人之法律行為而發生？', '["發明專利權之質權", "最高限額抵押權", "留置權", "普通地上權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00377', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲男育有一子乙（婚生子女），丙女育有一子丁（非婚生子女）。甲、丙結婚後，雖甲明知丁並非 自己之骨肉，但為使丁有法律上之父親，故認領丁並辦畢認領登記。甲死亡後，乙發現丁與甲並 無血緣關係，乙不希望丁繼承甲之遺產。下列主張何者有理由？', '["以繼承權被侵害之人的身分，提起婚生否認（否認子女）之訴，否定甲、丁之父子關係", "以甲於認領時被詐欺為由，提起撤銷認領之訴，否定甲、丁之父子關係", "以認領反於真實為由，提起確認親子關係不存在之訴，以確認甲之認領無效", "以甲於收養丁時未得丁之真正生父之同意為由，提起確認收養關係不存在之訴"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00378', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-110-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲19歲且已婚，其為下列何種行為應經甲之父母之同意？', '["甲向乙銀行貸款新臺幣200萬元", "甲與其妻丙兩願離婚", "甲收養其妻丙之非婚生子女丁（1歲，與甲無血緣關係）", "甲至戊公證人處，辦理公證遺囑"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "ed90381982ff", "answer_pdf_sha1": "2e99b98d38e1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "413", "s": "0705", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
